settings.customJs:
window.customilyShopify = window.customilyShopify || {};
window.customilyShopify.livePreviewMode = true;
window.customilyShopify.canvasPositioned = false;
window.customilyShopify.livePreviewBeforeGallery = true;
window.customilyShopify.hideAllPropsPrefix = '_';
window.customilyShopify.hideAllProps = true;
window.customilyShopify.skipThumbGeneration = true;
window.customilyShopify.preview = window.customilyShopify.preview || {};
window.customilyShopify.preview.preventShowWhenSetsLoad = true;
window.customilyShopify.hooks = window.customilyShopify.hooks || {};
window.customilyShopify.hooks.canvas = {
    displayCanvas: function () {
        if (!window.customilyShopify.canvasPositioned) {
            $('.gallery-wrap').prepend($('.canvas-wrapper'));

            var imgHeight = $('.canvas-wrapper').next().find('.flickity-viewport').height();

            $('#customily-custom-css').remove();
            const d = document.createElement('div');
            d.id = 'customily-custom-css';
            d.innerHTML = '<style> .customily-img-container{ height: ' + imgHeight + 'px !important; } </style>';
            document.head.appendChild(d);

            window.customilyShopify.canvasPositioned = true;
        }

        $('.canvas-wrapper').siblings().filter('.product_gallery_nav')
            .data('customily-hidden', true).addClass('customily-height0')
            .removeClass('customily-img-container');
        $('.canvas-wrapper').next().find('.flickity-viewport').addClass('customily-height0')
            .removeClass('customily-img-container');
        $('.canvas-wrapper').siblings().filter('.product_gallery')
            .hide();
        $('.canvas-wrapper').siblings().filter('.product_gallery_nav')
            .hide();
        $('.canvas-wrapper').data('customily-visible', true);
        $('.canvas-wrapper').fadeIn();
    }
};

window.addEventListener('customily-options-loaded', function(){
    fixCustomizationVariants();
});

function fixCustomizationVariants() {
    const url = window.location.href;
    const urlObj = new URL(url);
    if (urlObj.searchParams.has('customizationId')) {
        const selectedVariants = $('.swatch_options input:checked');
        selectedVariants.each(function () {
            $(this).parent().find('input').first().click();
            const $this = $(this);
            setTimeout(function () {
                $this.click();
            }, 1)
        });
    }
}

